export const buscarOfertasPromocao = async () => {
  try {
    const response = await fetch('http://localhost:3001/api/promocao_10');
    
    if (!response.ok) {
        throw new Error('Erro na rede');
    }

    const dados = await response.json();
    console.log("Service recebeu:", dados); // Log para conferir no F12
    return dados; // <--- CERTIFIQUE-SE QUE EXISTE ESSE RETURN
  } catch (error) {
    console.error("Erro no Service:", error);
    return []; // Retorna lista vazia em caso de erro real
  }
};
